.darma-loader-darma-custom-482 {--loader-bg: #ffffff;
  --loader-secondary-color: #f9a8d4;
   width: 60px;
   aspect-ratio: 1;
   color: var(--loader-color, #db2777);
   border: 10px solid;
   box-sizing: border-box;
   border-radius: 50%;
   animation: darma-loader-darma-custom-482-l6 2s infinite linear;
   position: relative;
}
.darma-loader-darma-custom-482:before  {
  content: "";
   position: absolute;
   height: 20px;
   inset: auto calc(50% - 10px) 100%;
   border-radius: 5px 5px 0 0;
   background: linear-gradient(currentColor 0 0) top/100% 30%, linear-gradient(currentColor 0 0) top/50% 100%;
   background-repeat: no-repeat;
}
.darma-loader-darma-custom-482:after  {
  content: "";
   position: absolute;
   inset: -8px -10px auto;
   height: 15px;
   background: radial-gradient(farthest-side,currentColor 94%,#0000) left, radial-gradient(farthest-side,currentColor 94%,#0000) right;
   background-size: 15px 15px;
   background-repeat: no-repeat;
}
@keyframes darma-loader-darma-custom-482-l6  {
  0% {background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 0 ,#0000 0)}
12.5%{background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 45deg ,#0000 46deg)}
25% {background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 90deg ,#0000 91deg)}
37.5%{background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 135deg,#0000 136deg)}
50% {background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 180deg,#0000 181deg)}
62.5%{background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 225deg,#0000 226deg)}
75% {background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 270deg,#0000 271deg)}
87.5%{background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 315deg,#0000 316deg)}
100% {background: conic-gradient(var(--loader-secondary-color, #f9a8d4) 360deg,#0000 360deg)}
}

